def _claire_v19_88_8B_lock_routes(app):
        grouped = {}
        for route in list(getattr(app, "routes", []) or []):
            path = getattr(route, "path", None)
            if path in _CLAIRE_V19_88_8B_CANONICAL_ROUTE_OWNERS:
                grouped.setdefault(path, []).append(route)

        selected = {}
        removed = {}

        for path, routes in grouped.items():
            chosen = _claire_v19_88_8B_select(routes, _CLAIRE_V19_88_8B_CANONICAL_ROUTE_OWNERS[path])
            if chosen:
                selected[path] = chosen
