                            "endpoint": _claire_v19_88_8B_endpoint_name(route),
                            "methods": _claire_v19_88_8B_route_methods(route),
                        })

        locked = []
        for route in list(getattr(app.router, "routes", []) or []):
            path = getattr(route, "path", None)
            if path in selected:
                if route is selected[path]:
                    locked.append(route)
            else:
