def _claire_v19_89_0_count_tree(path, max_files=5000):
        from pathlib import Path as _Path
        path = _Path(path)
        result = {
            "exists": path.exists(),
            "type": "directory" if path.is_dir() else "file" if path.is_file() else "missing",
            "files": 0,
            "directories": 0,
            "bytes": 0,
            "truncated": False,
            "sample": [],
        }
        if not path.exists():
            return result
        if path.is_file():
            result["files"] = 1
            try:
                result["bytes"] = path.stat().st_size
            except Exception:
                result["bytes"] = 0
            result["sample"] = [path.name]
            return result

        ignored = {".git", ".venv", "venv", "__pycache__", ".pytest_cache", "node_modules"}
        seen = 0
        try:
            for item in path.rglob("*"):
                if any(part in ignored for part in item.parts):
                    continue
                seen += 1
                if seen > max_files:
                    result["truncated"] = True
                    break
                try:
                    if item.is_dir():
                        result["directories"] += 1
                    elif item.is_file():
                        result["files"] += 1
                        result["bytes"] += item.stat().st_size
                        if len(result["sample"]) < 12:
                            result["sample"].append(str(item.relative_to(path)))
                except Exception:
                    continue
        except Exception as exc:
            result["error"] = str(exc)
        return result

